ce_tier\":\"standard\",\"inference_geo\":\"not_available\"},\"context_management\":null},\"parent_tool_use_id\":\"toolu_01TSMSYvQzdh78YH3Sxyiy8q\",\"session_id\":\"80f0eb9d-4064-4d06-8560-e247ce1170f2\",\"uuid\":\"09923183-4718-4bb6-99d1-ea51519b6983\"}\n{\"type\":\"user\",\"message\":{\"role\":\"user\",\"content\":[{\"tool_use_id\":\"toolu_013gJCuoGDTeTdaN2WBPFa9t\",\"type\":\"tool_result\",\"content\":\"1\\t//! SQL migrations for auth/tenancy tables (FEAT-014, ADR-018).\\n2\\t//!\\n3\\t//! Adds tables for:\\n4\\t//! - tenants: global account boundary\\n5\\t//! - users: global user identities\\n6\\t//! - user_identities: federated identity mapping\\n7\\t//! - tenant_users: M:N tenant membership\\n8\\t//! - tenant_databases: tenant-to-database mapping\\n9\\t//! - credential_revocations: revoked JWTs\\n10\\t//!\\n11\\t//! Note: `audit_retention_policies` is intentionally NOT included here — it\\n12\\t//! belongs to F1 audit-attribution (a separate bead / feature).\\n13\\t\\n14\\t/// Apply auth/tenancy migrations to a SQLite connection.\\n15\\t///\\n16\\t/// This is idempotent — running it multiple times on the same database\\n17\\t/// produces the same result without errors or duplicate rows.\\n18\\tpub fn apply_auth_migrations_sqlite(conn: \u0026rusqlite::Connection) -\u003e Result\u003c(), String\u003e {\\n19\\t    // Create tenants table.\\n20\\t    // UNIQUE(name) enforced by the UNIQUE constraint on the name column.\\n21\\t    conn.execute_batch(\\n22\\t        \\\"CREATE TABLE IF NOT EXISTS tenants (\\n23\\t            id                 TEXT PRIMARY KEY,\\n24\\t            name               TEXT NOT NULL UNIQUE,\\n25\\t            display_name       TEXT NOT NULL,\\n26\\t            created_at_ms      INTEGER NOT NULL,\\n27\\t            updated_at_ms      INTEGER NOT NULL\\n28\\t        )\\\",\\n29\\t    )\\n30\\t    .map_err(|e| format!(\\\"tenants table: {e}\\\"))?;\\n31\\t\\n32\\t    // Create users table.\\n33\\t    conn.execute_batch(\\n34\\t        \\\"CREATE TABLE IF NOT EXISTS users (\\n35\\t            id                 TEXT PRIMARY KEY,\\n36\\t            display_name       TEXT NOT NULL,\\n37\\t            email              TEXT,\\n38\\t            created_at_ms      INTEGER NOT NULL,\\n39\\t            suspended_at_ms    INTEGER\\n40\\t        )\\\",\\n41\\t    )\\n42\\t    .map_err(|e| format!(\\\"users table: {e}\\\"))?;\\n43\\t\\n44\\t    // Create user_identities table.\\n45\\t    // PRIMARY KEY (provider, external_id) enforces UNIQUE(provider, external_id).\\n46\\t    conn.execute_batch(\\n47\\t        \\\"CREATE TABLE IF NOT EXISTS user_identities (\\n48\\t            provider       TEXT NOT NULL,\\n49\\t            external_id    TEXT NOT NULL,\\n50\\t            user_id        TEXT NOT NULL REFERENCES users(id),\\n51\\t            created_at_ms  INTEGER NOT NULL,\\n52\\t            PRIMARY KEY (provider, external_id)\\n53\\t        )\\\",\\n54\\t    )\\n55\\t    .map_err(|e| format!(\\\"user_identities table: {e}\\\"))?;\\n56\\t\\n57\\t    // Create tenant_users table.\\n58\\t    // PRIMARY KEY (tenant_id, user_id) is the composite PK required by ADR-018.\\n59\\t    conn.execute_batch(\\n60\\t        \\\"CREATE TABLE IF NOT EXISTS tenant_users (\\n61\\t            tenant_id    TEXT NOT NULL REFERENCES tenants(id),\\n62\\t            user_id      TEXT NOT NULL REFERENCES users(id),\\n63\\t            role         TEXT NOT NULL,\\n64\\t            added_at_ms  INTEGER NOT NULL,\\n65\\t            PRIMARY KEY (tenant_id, user_id)\\n66\\t        )\\\",\\n67\\t    )\\n68\\t    .map_err(|e| format!(\\\"tenant_users table: {e}\\\"))?;\\n69\\t\\n70\\t    // Create tenant_databases table.\\n71\\t    conn.execute_batch(\\n72\\t        \\\"CREATE TABLE IF NOT EXISTS tenant_databases (\\n73\\t            tenant_id      TEXT NOT NULL REFERENCES tenants(id),\\n74\\t            database_name  TEXT NOT NULL,\\n75\\t            created_at_ms  INTEGER NOT NULL,\\n76\\t            PRIMARY KEY (tenant_id, database_name)\\n77\\t        )\\\",\\n78\\t    )\\n79\\t    .map_err(|e| format!(\\\"tenant_databases table: {e}\\\"))?;\\n80\\t\\n81\\t    // Create credential_revocations table.\\n82\\t    conn.execute_batch(\\n83\\t        \\\"CREATE TABLE IF NOT EXISTS credential_revocations (\\n84\\t            jti            TEXT PRIMARY KEY,\\n85\\t            revoked_at_ms  INTEGER NOT NULL,\\n86\\t            revoked_by     TEXT\\n87\\t        )\\\",\\n88\\t    )\\n89\\t    .map_err(|e| format!(\\\"credential_revocations table: {e}\\\"))?;\\n90\\t\\n91\\t    Ok(())\\n92\\t}\\n93\\t\\n94\\t/// Apply auth/tenancy migrations to a PostgreSQL connection.\\n95\\t///\\n96\\t/// This is idempotent — running it multiple times on the same database\\n97\\t/// produces the same result without errors or duplicate rows.\\n98\\tpub async fn apply_auth_migrations_postgres(client: \u0026tokio_postgres::Client) -\u003e Result\u003c(), String\u003e {\\n99\\t    // Create tenants table.\\n100\\t    // UNIQUE(name) enforced by the UNIQUE constraint on the name column.\\n101\\t    client\\n102\\t        .batch_execute(\\n103\\t            \\\"CREATE TABLE IF NOT EXISTS tenants (\\n104\\t                id                 TEXT PRIMARY KEY,\\n105\\t                name               TEXT NOT NULL UNIQUE,\\n106\\t                display_name       TEXT NOT NULL,\\n107\\t                created_at_ms      BIGINT NOT NULL,\\n108\\t                updated_at_ms      BIGINT NOT NULL\\n109\\t            )\\\",\\n110\\t        )\\n111\\t        .await\\n112\\t        .map_err(|e| format!(\\\"tenants table: {e}\\\"))?;\\n113\\t\\n114\\t    // Create users table.\\n115\\t    client\\n116\\t        .batch_execute(\\n117\\t            \\\"CREATE TABLE IF NOT EXISTS users (\\n118\\t                id                 TEXT PRIMARY KEY,\\n119\\t                display_name       TEXT NOT NULL,\\n120\\t                email              TEXT,\\n121\\t                created_at_ms      BIGINT NOT NULL,\\n122\\t                suspended_at_ms    BIGINT\\n123\\t            )\\\",\\n124\\t        )\\n125\\t        .await\\n126\\t        .map_err(|e| format!(\\\"users table: {e}\\\"))?;\\n127\\t\\n128\\t    // Create user_identities table.\\n129\\t    // PRIMARY KEY (provider, external_id) enforces UNIQUE(provider, external_id).\\n130\\t    client\\n131\\t        .batch_execute(\\n132\\t            \\\"CREATE TABLE IF NOT EXISTS user_identities (\\n133\\t                provider       TEXT NOT NULL,\\n134\\t                external_id    TEXT NOT NULL,\\n135\\t                user_id        TEXT NOT NULL REFERENCES users(id),\\n136\\t                created_at_ms  BIGINT NOT NULL,\\n137\\t                PRIMARY KEY (provider, external_id)\\n138\\t            )\\\",\\n139\\t        )\\n140\\t        .await\\n141\\t        .map_err(|e| format!(\\\"user_identities table: {e}\\\"))?;\\n142\\t\\n143\\t    // Create tenant_users table.\\n144\\t    // PRIMARY KEY (tenant_id, user_id) is the composite PK required by ADR-018.\\n145\\t    client\\n146\\t        .batch_execute(\\n147\\t            \\\"CREATE TABLE IF NOT EXISTS tenant_users (\\n148\\t                tenant_id    TEXT NOT NULL REFERENCES tenants(id),\\n149\\t                user_id      TEXT NOT NULL REFERENCES users(id),\\n150\\t                role         TEXT NOT NULL,\\n151\\t                added_at_ms  BIGINT NOT NULL,\\n152\\t                PRIMARY KEY (tenant_id, user_id)\\n153\\t            )\\\",\\n154\\t        )\\n155\\t        .await\\n156\\t        .map_err(|e| format!(\\\"tenant_users table: {e}\\\"))?;\\n157\\t\\n158\\t    // Create tenant_databases table.\\n159\\t    client\\n160\\t        .batch_execute(\\n161\\t            \\\"CREATE TABLE IF NOT EXISTS tenant_databases (\\n162\\t                tenant_id      TEXT NOT NULL REFERENCES tenants(id),\\n163\\t                database_name  TEXT NOT NULL,\\n164\\t                created_at_ms  BIGINT NOT NULL,\\n165\\t                PRIMARY KEY (tenant_id, database_name)\\n166\\t            )\\\",\\n167\\t        )\\n168\\t        .await\\n169\\t        .map_err(|e| format!(\\\"tenant_databases table: {e}\\\"))?;\\n170\\t\\n171\\t    // Create credential_revocations table.\\n172\\t    client\\n173\\t        .batch_execute(\\n174\\t            \\\"CREATE TABLE IF NOT EXISTS credential_revocations (\\n175\\t                jti            TEXT PRIMARY KEY,\\n176\\t                revoked_at_ms  BIGINT NOT NULL,\\n177\\t                revoked_by     TEXT\\n178\\t            )\\\",\\n179\\t        )\\n180\\t        .await\\n181\\t        .map_err(|e| format!(\\\"credential_revocations table: {e}\\\"))?;\\n182\\t\\n183\\t    Ok(())\\n184\\t}\\n185\\t\\n186\\t#[cfg(test)]\\n187\\tmod tests {\\n188\\t    use super::*;\\n189\\t    use rusqlite::Connection;\\n190\\t\\n191\\t    // ── Helpers ───────────────────────────────────────────────────────────────\\n192\\t\\n193\\t    fn open_and_migrate() -\u003e Connection {\\n194\\t        let conn = Connection::open_in_memory().expect(\\\"in-memory DB should open\\\");\\n195\\t        apply_auth_migrations_sqlite(\u0026conn).expect(\\\"migrations should succeed\\\");\\n196\\t        conn\\n197\\t    }\\n198\\t\\n199\\t    // ── Schema existence ──────────────────────────────────────────────────────\\n200\\t\\n201\\t    #[test]\\n202\\t    fn apply_sqlite_migrations_creates_all_tables() {\\n203\\t        let conn = open_and_migrate();\\n204\\t\\n205\\t        let count: i64 = conn\\n206\\t            .query_row(\\n207\\t                \\\"SELECT COUNT(*) FROM sqlite_master WHERE type='table' AND name IN (\\n208\\t                    'tenants', 'users', 'user_identities', 'tenant_users',\\n209\\t                    'tenant_databases', 'credential_revocations'\\n210\\t                )\\\",\\n211\\t                [],\\n212\\t                |row| row.get(0),\\n213\\t            )\\n214\\t            .expect(\\\"query should succeed\\\");\\n215\\t        assert_eq!(count, 6, \\\"all 6 auth tab