\t/// The `superadmin_dsn` must have sufficient privileges to execute\\n1302\\t/// `DROP DATABASE`.\\n1303\\t///\\n1304\\t/// # Errors\\n1305\\t///\\n1306\\t/// Returns `AxonError::NotFound` if the database does not exist.\\n1307\\t/// Returns `AxonError::InvalidArgument` if `name` contains invalid characters.\\n1308\\t/// Returns `AxonError::Storage` for other PostgreSQL errors.\\n1309\\tpub fn deprovision_postgres_database(superadmin_dsn: \u0026str, name: \u0026str) -\u003e Result\u003c(), AxonError\u003e {\\n1310\\t    validate_pg_db_name(name)?;\\n1311\\t    let full_name = format!(\\\"axon_{name}\\\");\\n1312\\t    let rt = tokio::runtime::Builder::new_current_thread()\\n1313\\t        .enable_all()\\n1314\\t        .build()\\n1315\\t        .map_err(|e| AxonError::Storage(e.to_string()))?;\\n1316\\t    rt.block_on(async {\\n1317\\t        let (client, connection) = tokio_postgres::connect(superadmin_dsn, NoTls)\\n1318\\t            .await\\n1319\\t            .map_err(|e| AxonError::Storage(e.to_string()))?;\\n1320\\t        tokio::spawn(async move {\\n1321\\t            let _ = connection.await;\\n1322\\t        });\\n1323\\t        let row = client\\n1324\\t            .query_one(\\n1325\\t                \\\"SELECT EXISTS(SELECT 1 FROM pg_database WHERE datname = $1)\\\",\\n1326\\t                \u0026[\u0026full_name.as_str()],\\n1327\\t            )\\n1328\\t            .await\\n1329\\t            .map_err(|e| AxonError::Storage(e.to_string()))?;\\n1330\\t        let exists: bool = row.get(0);\\n1331\\t        if !exists {\\n1332\\t            return Err(AxonError::NotFound(format!(\\n1333\\t                \\\"PostgreSQL database '{full_name}'\\\"\\n1334\\t            )));\\n1335\\t        }\\n1336\\t        client\\n1337\\t            .simple_query(\u0026format!(\\\"DROP DATABASE \\\\\\\"{full_name}\\\\\\\"\\\"))\\n1338\\t            .await\\n1339\\t            .map_err(|e| AxonError::Storage(e.to_string()))?;\\n1340\\t        Ok(())\\n1341\\t    })\\n1342\\t}\\n1343\\t\\n1344\\t// The conformance test suite requires PostgreSQL.\\n1345\\t// Explicit verification path:\\n1346\\t// AXON_TEST_POSTGRES=\\\"host=localhost user=axon dbname=axon_test\\\" cargo test -p axon-storage postgres::tests:: -- --nocapture\\n1347\\t// When `AXON_TEST_POSTGRES` is unset, these tests attempt to provision PostgreSQL\\n1348\\t// via testcontainers and skip cleanly if the container runtime is unavailable.\\n1349\\t#[cfg(test)]\\n1350\\tmod tests {\\n1351\\t    use std::{\\n1352\\t        ops::{Deref, DerefMut},\\n1353\\t        sync::{Mutex, MutexGuard, OnceLock},\\n1354\\t    };\\n1355\\t\\n1356\\t    use super::*;\\n1357\\t    use axon_core::types::Link;\\n1358\\t    use testcontainers_modules::postgres::Postgres as PgContainer;\\n1359\\t    use testcontainers_modules::testcontainers::{runners::SyncRunner, Container};\\n1360\\t\\n1361\\t    struct TestDatabase {\\n1362\\t        url: String,\\n1363\\t        _container: Option\u003cContainer\u003cPgContainer\u003e\u003e,\\n1364\\t    }\\n1365\\t\\n1366\\t    enum TestSetupError {\\n1367\\t        Skip(String),\\n1368\\t        Fail(AxonError),\\n1369\\t    }\\n1370\\t\\n1371\\t    impl TestDatabase {\\n1372\\t        fn connect() -\u003e Result\u003cSelf, TestSetupError\u003e {\\n1373\\t            if let Ok(url) = std::env::var(\\\"AXON_TEST_POSTGRES\\\") {\\n1374\\t                return Ok(Self {\\n1375\\t                    url,\\n1376\\t                    _container: None,\\n1377\\t                });\\n1378\\t            }\\n1379\\t\\n1380\\t            let container = PgContainer::default()\\n1381\\t                .with_db_name(\\\"axon_test\\\")\\n1382\\t                .with_user(\\\"postgres\\\")\\n1383\\t                .with_password(\\\"postgres\\\")\\n1384\\t                .start()\\n1385\\t                .map_err(|error| {\\n1386\\t                    TestSetupError::Skip(format!(\\n1387\\t                        \\\"AXON_TEST_POSTGRES is unset and PostgreSQL test container startup failed: {error}\\\"\\n1388\\t                    ))\\n1389\\t                })?;\\n1390\\t            let host = container.get_host().map_err(|error| {\\n1391\\t                TestSetupError::Fail(AxonError::Storage(format!(\\n1392\\t                    \\\"failed to resolve PostgreSQL test container host: {error}\\\"\\n1393\\t                )))\\n1394\\t            })?;\\n1395\\t            let port = container.get_host_port_ipv4(5432).map_err(|error| {\\n1396\\t                TestSetupError::Fail(AxonError::Storage(format!(\\n1397\\t                    \\\"failed to resolve PostgreSQL test container port: {error}\\\"\\n1398\\t                )))\\n1399\\t            })?;\\n1400\\t\\n1401\\t            Ok(Self {\\n1402\\t                url: format!(\\n1403\\t                    \\\"host={host} port={port} user=postgres password=postgres dbname=axon_test\\\"\\n1404\\t                ),\\n1405\\t                _container: Some(container),\\n1406\\t            })\\n1407\\t        }\\n1408\\t\\n1409\\t        fn url(\u0026self) -\u003e \u0026str {\\n1410\\t            \u0026self.url\\n1411\\t        }\\n1412\\t    }\\n1413\\t\\n1414\\t    struct TestStore {\\n1415\\t        adapter: PostgresStorageAdapter,\\n1416\\t        _database: TestDatabase,\\n1417\\t    }\\n1418\\t\\n1419\\t    impl Deref for TestStore {\\n1420\\t        type Target = PostgresStorageAdapter;\\n1421\\t\\n1422\\t        fn deref(\u0026self) -\u003e \u0026Self::Target {\\n1423\\t            \u0026self.adapter\\n1424\\t        }\\n1425\\t    }\\n1426\\t\\n1427\\t    impl DerefMut for TestStore {\\n1428\\t        fn deref_mut(\u0026mut self) -\u003e \u0026mut Self::Target {\\n1429\\t            \u0026mut self.adapter\\n1430\\t        }\\n1431\\t    }\\n1432\\t\\n1433\\t    fn postgres_test_guard() -\u003e MutexGuard\u003c'static, ()\u003e {\\n1434\\t        static GUARD: OnceLock\u003cMutex\u003c()\u003e\u003e = OnceLock::new();\\n1435\\t        GUARD\\n1436\\t            .get_or_init(|| Mutex::new(()))\\n1437\\t            .lock()\\n1438\\t            .expect(\\\"PostgreSQL test guard lock should not be poisoned\\\")\\n1439\\t    }\\n1440\\t\\n1441\\t    fn skip_postgres_test(test_name: \u0026str, reason: \u0026str) {\\n1442\\t        tracing::warn!(test = test_name, reason, \\\"skipping PostgreSQL storage test\\\");\\n1443\\t    }\\n1444\\t\\n1445\\t    fn database_or_skip(test_name: \u0026str) -\u003e Option\u003cTestDatabase\u003e {\\n1446\\t        match TestDatabase::connect() {\\n1447\\t            Ok(database) =\u003e Some(database),\\n1448\\t            Err(TestSetupError::Skip(reason)) =\u003e {\\n1449\\t                skip_postgres_test(test_name, \u0026reason);\\n1450\\t                None\\n1451\\t            }\\n1452\\t            Err(TestSetupError::Fail(error)) =\u003e {\\n1453\\t                panic!(\\\"PostgreSQL test setup should succeed: {error}\\\");\\n1454\\t            }\\n1455\\t        }\\n1456\\t    }\\n1457\\t\\n1458\\t    fn store() -\u003e Result\u003cTestStore, TestSetupError\u003e {\\n1459\\t        let database = TestDatabase::connect()?;\\n1460\\t        let adapter =\\n1461\\t            PostgresStorageAdapter::connect(database.url()).map_err(TestSetupError::Fail)?;\\n1462\\t        // Clean tables for a fresh test.\\n1463\\t        adapter\\n1464\\t            .block(adapter.client.batch_execute(\\n1465\\t                \\\"TRUNCATE entities, schemas, collection_views, collections, namespaces, databases, audit_log RESTART IDENTITY CASCADE\\\",\\n1466\\t            ))\\n1467\\t            .map_err(TestSetupError::Fail)?;\\n1468\\t        adapter\\n1469\\t            .ensure_default_namespace()\\n1470\\t            .map_err(TestSetupError::Fail)?;\\n1471\\t        Ok(TestStore {\\n1472\\t            adapter,\\n1473\\t            _database: database,\\n1474\\t        })\\n1475\\t    }\\n1476\\t\\n1477\\t    fn store_or_skip(test_name: \u0026str) -\u003e Option\u003cTestStore\u003e {\\n1478\\t        match store() {\\n1479\\t            Ok(store) =\u003e Some(store),\\n1480\\t            Err(TestSetupError::Skip(reason)) =\u003e {\\n1481\\t                skip_postgres_test(test_name, \u0026reason);\\n1482\\t                None\\n1483\\t            }\\n1484\\t            Err(TestSetupError::Fail(error)) =\u003e {\\n1485\\t                panic!(\\\"PostgreSQL test setup should succeed: {error}\\\");\\n1486\\t            }\\n1487\\t        }\\n1488\\t    }\\n1489\\t\\n1490\\t    fn register_unique_namespaced_collection(\\n1491\\t        store: \u0026mut TestStore,\\n1492\\t        qualified: \u0026CollectionId,\\n1493\\t    ) -\u003e (Namespace, CollectionId) {\\n1494\\t        let (namespace, bare_collection) = Namespace::parse(qualified.as_str());\\n1495\\t        let bare_collection = CollectionId::new(bare_collection);\\n1496\\t\\n1497\\t        store\\n1498\\t            .create_database(namespace.database.as_str())\\n1499\\t            .expect(\\\"database create should succeed\\\");\"}]},\"parent_tool_use_id\":\"toolu_01V9ewrQMRMUNg8o8KExVgdR\",\"session_id\":\"80f0eb9d-4064-4d06-8560-e247ce1170f2\",\"uuid\":\"16ba58da-8642-47e8-be12-7f712623b69f\",\"timestamp\":\"2026-04-15T01:31:04.617Z\"}\n{\"type\":\"system\",\"subtype\":\"task_progress\",\"task_id\":\"ab7893c6e8bebbea1\",\"tool_use_id\":\"toolu_01TSMSYvQzdh78YH3Sxyiy8q\",\"description\":\"Reading docs/helix/02-design/adr/ADR-018-tenant-user-credential-model.md\",\"usage\":{\"total_tokens\":30020,\"tool_uses\":18,\"duration_ms\":14448},\"last_tool_name\":\"Read\",\"uuid\":\"8afa7152-23b1-425e-bc05-780ebec17bd7\",\"session_id\":\"80f0eb9d-4064-4d06-8560-e247ce1170f2\"}\n{\"type\":\"assistant\",\"message\":{\"model\":\"claude-haiku-4-5-20251001\",\"id\":\"msg_011SNRZDMg65PuYWAEQgKe6a\",\"type\":\"message\",\"role\":\"assistant\",\"content\":[{\"type\":\"tool_use\",\"id\":\"toolu_01Uzmkp7MEZPni2mXrvk8UYL\",\"name\":\"Read\",\"input\":{\"file_path\":\"/tmp/ddx-exec-wt/.execute-bead-wt-axon-dccbdf73-202604