msg_011SNRZDMg65PuYWAEQgKe6a\",\"type\":\"message\",\"role\":\"assistant\",\"content\":[{\"type\":\"tool_use\",\"id\":\"toolu_01GZqGkQtHB58eVVTcpTZqa8\",\"name\":\"Read\",\"input\":{\"file_path\":\"/tmp/ddx-exec-wt/.execute-bead-wt-axon-dccbdf73-20260415T013041-1340da9f/crates/axon-core/src/auth.rs\",\"offset\":0,\"limit\":400},\"caller\":{\"type\":\"direct\"}}],\"stop_reason\":null,\"stop_sequence\":null,\"stop_details\":null,\"usage\":{\"input_tokens\":6,\"cache_creation_input_tokens\":567,\"cache_read_input_tokens\":29402,\"cache_creation\":{\"ephemeral_5m_input_tokens\":567,\"ephemeral_1h_input_tokens\":0},\"output_tokens\":1,\"service_tier\":\"standard\",\"inference_geo\":\"not_available\"},\"context_management\":null},\"parent_tool_use_id\":\"toolu_01TSMSYvQzdh78YH3Sxyiy8q\",\"session_id\":\"80f0eb9d-4064-4d06-8560-e247ce1170f2\",\"uuid\":\"e352c111-d313-465c-87e6-a2f60ebf2a3e\"}\n{\"type\":\"system\",\"subtype\":\"task_progress\",\"task_id\":\"ab7893c6e8bebbea1\",\"tool_use_id\":\"toolu_01TSMSYvQzdh78YH3Sxyiy8q\",\"description\":\"Reading crates/axon-core/src/auth.rs\",\"usage\":{\"total_tokens\":30022,\"tool_uses\":20,\"duration_ms\":15377},\"last_tool_name\":\"Read\",\"uuid\":\"f68a9f62-9f52-4923-ad35-e30bd917ebb5\",\"session_id\":\"80f0eb9d-4064-4d06-8560-e247ce1170f2\"}\n{\"type\":\"assistant\",\"message\":{\"model\":\"claude-haiku-4-5-20251001\",\"id\":\"msg_011SNRZDMg65PuYWAEQgKe6a\",\"type\":\"message\",\"role\":\"assistant\",\"content\":[{\"type\":\"tool_use\",\"id\":\"toolu_017xXnEF67K9wcoU5PYR97aD\",\"name\":\"Read\",\"input\":{\"file_path\":\"/tmp/ddx-exec-wt/.execute-bead-wt-axon-dccbdf73-20260415T013041-1340da9f/crates/axon-core/src/auth.rs\",\"offset\":400,\"limit\":500},\"caller\":{\"type\":\"direct\"}}],\"stop_reason\":null,\"stop_sequence\":null,\"stop_details\":null,\"usage\":{\"input_tokens\":6,\"cache_creation_input_tokens\":567,\"cache_read_input_tokens\":29402,\"cache_creation\":{\"ephemeral_5m_input_tokens\":567,\"ephemeral_1h_input_tokens\":0},\"output_tokens\":1,\"service_tier\":\"standard\",\"inference_geo\":\"not_available\"},\"context_management\":null},\"parent_tool_use_id\":\"toolu_01TSMSYvQzdh78YH3Sxyiy8q\",\"session_id\":\"80f0eb9d-4064-4d06-8560-e247ce1170f2\",\"uuid\":\"92b47ace-996f-434b-8094-8824e2752669\"}\n{\"type\":\"user\",\"message\":{\"role\":\"user\",\"content\":[{\"tool_use_id\":\"toolu_01GZqGkQtHB58eVVTcpTZqa8\",\"type\":\"tool_result\",\"content\":\"0\\t//! Role-based and attribute-based access control for Axon (FEAT-012).\\n1\\t//!\\n2\\t//! # Layers\\n3\\t//!\\n4\\t//! **Layer 1 — RBAC** ([`Role`], [`CallerIdentity`], [`Operation`])\\n5\\t//!\\n6\\t//! Four built-in roles (`Admin \u003e Write \u003e Read \u003e None`) control access to\\n7\\t//! Axon operations.  Roles are derived from the identity provider (Tailscale\\n8\\t//! ACL tags, OIDC claims, etc.) by the server layer and passed into handlers\\n9\\t//! as a [`CallerIdentity`].  Handlers call [`CallerIdentity::check`] to\\n10\\t//! enforce the minimum required role.\\n11\\t//!\\n12\\t//! **Layer 2 — Field-level masking** ([`MaskPolicy`])\\n13\\t//!\\n14\\t//! A `MaskPolicy` hides individual entity fields from callers whose role\\n15\\t//! falls below a configured minimum.  Applied by [`CallerIdentity::apply_masks`]\\n16\\t//! before returning entity data to the caller.  Admins always see all fields.\\n17\\t//!\\n18\\t//! **Layer 3 — Collection write control** ([`WritePolicy`])\\n19\\t//!\\n20\\t//! A `WritePolicy` sets a per-collection minimum write role and marks fields\\n21\\t//! as immutable after creation.  Checked by the handler before any mutation.\\n22\\t//!\\n23\\t//! **Layer 4 — Database-scoped grants** ([`DatabaseGrant`], [`GrantRegistry`])\\n24\\t//!\\n25\\t//! Grants scope a role to a specific database (or `\\\"*\\\"` for all databases).\\n26\\t//! Without a matching grant a caller has `Role::None` on that database.\\n27\\t//! Admins with a global grant bypass per-database checks.  The grant registry\\n28\\t//! is stored in `__axon_policies__` and enforced at the routing layer.\\n29\\t\\n30\\tuse serde::{Deserialize, Serialize};\\n31\\t\\n32\\tuse crate::error::AxonError;\\n33\\t\\n34\\t/// Built-in roles for Axon RBAC (FEAT-012).\\n35\\t///\\n36\\t/// Roles are ordered by privilege: `Admin \u003e Write \u003e Read \u003e None`.\\n37\\t/// When a user has multiple roles (e.g., from multiple ACL tags),\\n38\\t/// the highest-privilege role wins.\\n39\\t#[derive(Debug, Clone, Copy, PartialEq, Eq, PartialOrd, Ord, Hash, Serialize, Deserialize)]\\n40\\tpub enum Role {\\n41\\t    /// No access. Explicitly denied.\\n42\\t    None = 0,\\n43\\t    /// Read entities, query, traverse, browse audit log.\\n44\\t    Read = 1,\\n45\\t    /// Create, update, delete entities and links in any collection.\\n46\\t    Write = 2,\\n47\\t    /// All operations including drop and schema changes.\\n48\\t    Admin = 3,\\n49\\t}\\n50\\t\\n51\\timpl Role {\\n52\\t    /// Parse a role from a Tailscale ACL tag or string name.\\n53\\t    ///\\n54\\t    /// Accepted inputs (both full `tag:` prefix and bare name):\\n55\\t    ///\\n56\\t    /// | Input | Role |\\n57\\t    /// |-------|------|\\n58\\t    /// | `\\\"tag:axon-admin\\\"` / `\\\"tag:admin\\\"` / `\\\"admin\\\"` | `Admin` |\\n59\\t    /// | `\\\"tag:axon-write\\\"` / `\\\"tag:axon-agent\\\"` / `\\\"tag:write\\\"` / `\\\"write\\\"` | `Write` |\\n60\\t    /// | `\\\"tag:axon-read\\\"` / `\\\"tag:read\\\"` / `\\\"read\\\"` | `Read` |\\n61\\t    /// | anything else | `None` |\\n62\\t    ///\\n63\\t    /// `tag:axon-agent` is an alias for `write` — the conventional tag for\\n64\\t    /// automated agent workloads that need read/write but not admin access.\\n65\\t    pub fn from_tag(tag: \u0026str) -\u003e Self {\\n66\\t        match tag {\\n67\\t            \\\"tag:axon-admin\\\" | \\\"tag:admin\\\" | \\\"admin\\\" =\u003e Role::Admin,\\n68\\t            \\\"tag:axon-write\\\" | \\\"tag:axon-agent\\\" | \\\"tag:write\\\" | \\\"write\\\" =\u003e Role::Write,\\n69\\t            \\\"tag:axon-read\\\" | \\\"tag:read\\\" | \\\"read\\\" =\u003e Role::Read,\\n70\\t            _ =\u003e Role::None,\\n71\\t        }\\n72\\t    }\\n73\\t\\n74\\t    /// Determine the highest-privilege role from a set of tags.\\n75\\t    pub fn from_tags(tags: \u0026[String]) -\u003e Self {\\n76\\t        tags.iter()\\n77\\t            .map(|t| Role::from_tag(t))\\n78\\t            .max()\\n79\\t            .unwrap_or(Role::None)\\n80\\t    }\\n81\\t}\\n82\\t\\n83\\timpl std::fmt::Display for Role {\\n84\\t    fn fmt(\u0026self, f: \u0026mut std::fmt::Formatter\u003c'_\u003e) -\u003e std::fmt::Result {\\n85\\t        match self {\\n86\\t            Role::None =\u003e write!(f, \\\"none\\\"),\\n87\\t            Role::Read =\u003e write!(f, \\\"read\\\"),\\n88\\t            Role::Write =\u003e write!(f, \\\"write\\\"),\\n89\\t            Role::Admin =\u003e write!(f, \\\"admin\\\"),\\n90\\t        }\\n91\\t    }\\n92\\t}\\n93\\t\\n94\\t/// The kind of operation being attempted.\\n95\\t#[derive(Debug, Clone, Copy, PartialEq, Eq)]\\n96\\tpub enum Operation {\\n97\\t    /// Read an entity, query, traverse, audit.\\n98\\t    Read,\\n99\\t    /// Create, update, delete entities/links.\\n100\\t    Write,\\n101\\t    /// Drop collections, modify schemas, manage namespaces.\\n102\\t    Admin,\\n103\\t}\\n104\\t\\n105\\timpl Operation {\\n106\\t    /// The minimum role required for this operation.\\n107\\t    pub fn required_role(self) -\u003e Role {\\n108\\t        match self {\\n109\\t            Operation::Read =\u003e Role::Read,\\n110\\t            Operation::Write =\u003e Role::Write,\\n111\\t            Operation::Admin =\u003e Role::Admin,\\n112\\t        }\\n113\\t    }\\n114\\t}\\n115\\t\\n116\\t/// A simple field-equality filter used as an agent scope constraint\\n117\\t/// (FEAT-022 / ADR-016).\\n118\\t///\\n119\\t/// When attached to a [`CallerIdentity`], the agent guardrails layer rejects\\n120\\t/// any mutation whose target entity data does not satisfy\\n121\\t/// `data[field] == value`. V1 supports only field-equality predicates;\\n122\\t/// compound and range filters are deferred.\\n123\\t#[derive(Debug, Clone, PartialEq, Eq, Serialize, Deserialize)]\\n124\\tpub struct EntityFilter {\\n125\\t    /// The top-level data field to compare.\\n126\\t    pub field: String,\\n127\\t    /// The required value for that field.\\n128\\t    pub value: serde_json::Value,\\n129\\t}\\n130\\t\\n131\\timpl EntityFilter {\\n132\\t    /// Convenience constructor.\\n133\\t    pub fn new(field: impl Into\u003cString\u003e, value: serde_json::Value) -\u003e Self {\\n134\\t        Self {\\n135\\t            field: field.into(),\\n136\\t            value,\\n137\\t        }\\n138\\t    }\\n139\\t\\n140\\t    /// Returns `true` when the JSON object `data` satisfies this filter.\\n141\\t    ///\\n142\\t    /// Returns `false` when `data` is not a JSON object, when the field is\\n143\\t    /// absent, or when the value does not equal [`Self::value`].\\n144\\t    pub fn matches(\u0026self, data: \u0026serde_json::Value) -\u003e bool {\\n145\\t        data.get(\u0026self.field).is_some_and(|v| v == \u0026self.value)\\n146\\t    }\\n147\\t}\\n148\\t\\n149\\t/// Identity context for a request.\\n150\\t///\\n151\\t/// Populated by the auth middleware from the identity provider.\\n152\\t/// In `--no-auth` mode, all requests get `CallerIdentity::anonymous()`.\\n153\\t#[derive(Debug, Clone, Serialize, Deserialize)]\\n154\\tpub struct CallerIdentity {\\n155\\t    /// Actor name for audit log entries.\\n156\\t    pub actor: String,\\n157\\t    /// The caller's effective role (highest privilege from all their tags).\\n158\\t    pub role: Role,\\n159\\t    /// Optional scope constraint enforced by the agent guardrails layer\\n160\\t    /// (FEAT-022, ADR-016). When `Some`, this caller may only mutate entities\\n161\\t    /// whose data matches the filter. `None` means no scope restriction.\\n162\\t    #[serde(default, skip_serializing_if = \\\"Option::is_none\\\")]\\n163\\t    pub entity_filter: Option\u003cEntityFilter\u003e,\\n164\\t}\\n165\\t\\n166\\timpl CallerIdentity {\\n167\\t    /// Create an anonymous identity with admin privileges (`--no-auth` mode).\\n168\\t    pub fn anonymous() -\u003e Self {\\n169\\t        Self {\\n170\\t            actor: \\\"anonymous\\\".into(),\\n171\\t            role: Role::Admin,\\n172\\t            entity_filter: None,\\n173\\t        }\\n174\\t    }\\n175\\t\\n176\\t    /// Create an identity from a name and role.\\n177\\t    pub fn new(actor: impl Into\u003cString\u003e, role: Role) -\u003e Self {\\n178\\t        Self {\\n179\\t            actor: actor.into(),\\n180\\t            role,\\n181\\t            entity_filter: None,\\n182\\t        }\\n183\\t    }\\n184\\t\\n185\\t    /// Attach an entity scope filter (builder style, FEAT-022).\\n186\\t    pub fn with_entity_filter(mut self, filter: EntityFilter) -\u003e Self {\\n187\\t        self.entity_filter = Some(filter);\\n188\\t        self\\n189\\t    }\\n190\\t\\n191\\t    /// Check whether this caller is authorized for the given operation.\\n192\\t    ///\\n193\\t    /// Returns `Ok(())` if authorized, or `Err(AxonError::InvalidOperation)`\\n194\\t    /// with a descriptive message if not.\\n195\\t    pub fn check(\u0026self, op: Operation) -\u003e Result\u003c(), AxonError\u003e {\\n196\\t        let required = op.required_role();\\n197\\t        if self.role \u003e= required {\\n198\\t            Ok(())\\n199\\t        } else {\\n200\\t            Err(AxonError::InvalidOperation(format!(\\n201\\t                \\\"permission denied: role '{}' cannot perform {:?} operations (requires '{}')\\\",\\n202\\t                self.role, op, required\\n203\\t            )))\\n204\\t        }\\n205\\t    }\\n206\\t\\n207\\t    /// Apply field-level masking to entity data based on mask policies.\\n208\\t    ///\\n209\\t    /// Admin users see all fields. For other roles, fields listed in a\\n210\\t    /// mask policy that requires a higher role than the caller's are\\n211\\t    /// removed from the data.\\n212\\t    pub fn apply_masks(\u0026self, data: \u0026mut serde_json::Value, policies: \u0026[MaskPolicy]) {\\n213\\t        if self.role \u003e= Role::Admin {\\n214\\t            return; // Admin sees all.\\n215\\t        }\\n216\\t        if let Some(obj) = data.as_object_mut() {\\n217\\t            for policy in policies {\\n218\\t                if self.role \u003c policy.min_role {\\n219\\t                    obj.remove(\u0026policy.field);\\n220\\t                }\\n221\\t            }\\n222\\t        }\\n223\\t    }\\n224\\t}\\n225\\t\\n226\\t/// A field-level mask policy (US-046, FEAT-012).\\n227\\t///\\n228\\t/// Specifies that a field should be hidden from callers whose role is\\n229\\t/// below `min_role`. Admin always sees all fields.\\n230\\t#[derive(Debug, Clone, PartialEq, Eq, Serialize, Deserialize)]\\n231\\tpub struct MaskPolicy {\\n232\\t    /// The field name to mask.\\n233\\t    pub field: String,\\n234\\t    /// Minimum role required to see this field.\\n235\\t    pub min_role: Role,\\n236\\t}\\n237\\t\\n238\\t// ── Attribute-based write control (US-047, FEAT-012) ────────────────────────\\n239\\t\\n240\\t/// Per-collection write policy for attribute-based access control (ABAC).\\n241\\t///\\n242\\t/// Stored in the `__axon_policies__` pseudo-collection. Defines:\\n243\\t/// - Minimum role required to write to this collection\\n244\\t/// - Fields that are immutable after creation\\n245\\t#[derive(Debug, Clone, PartialEq, Eq, Serialize, Deserialize)]\\n246\\tpub struct WritePolicy {\\n247\\t    /// Collection this policy applies to.\\n248\\t    pub collection: String,\\n249\\t    /// Minimum role required for write operations.\\n250\\t    pub min_write_role: Role,\\n251\\t    /// Fields that cannot be modified after the initial create.\\n252\\t    #[serde(default)]\\n253\\t    pub immutable_fields: Vec\u003cString\u003e,\\n254\\t}\\n255\\t\\n256\\timpl WritePolicy {\\n257\\t    /// Check if a caller has sufficient role to write to this collection.\\n258\\t    pub fn check_write(\u0026self, caller: \u0026CallerIdentity) -\u003e Result\u003c(), AxonError\u003e {\\n259\\t        if caller.role \u003e= self.min_write_role {\\n260\\t            Ok(())\\n261\\t        } else {\\n262\\t            Err(AxonError::InvalidOperation(format!(\\n263\\t                \\\"write policy for '{}': role '{}' insufficient (requires '{}')\\\",\\n264\\t                self.collection, caller.role, self.min_write_role\\n265\\t            )))\\n266\\t        }\\n267\\t    }\\n268\\t\\n269\\t    /// Check if any immutable fields have been modified.\\n270\\t    ///\\n271\\t    /// Returns the list of field names that were illegally modified.\\n272\\t    pub fn check_immutable_fields(\\n273\\t        \u0026self,\\n274\\t        old_data: \u0026serde_json::Value,\\n275\\t        new_data: \u0026serde_json::Value,\\n276\\t    ) -\u003e Vec\u003cString\u003e {\\n277\\t        let mut violations = Vec::new();\\n278\\t        for field in \u0026self.immutable_fields {\\n279\\t            let old_val = old_data.get(field);\\n280\\t            let new_val = new_data.get(field);\\n281\\t            // If the field existed before and is now different or missing, it's a violation.\\n282\\t            if old_val.is_some() \u0026\u0026 old_val != new_val {\\n283\\t                violations.push(field.clone());\\n284\\t            }\\n285\\t        }\\n286\\t        violations\\n287\\t    }\\n288\\t}\\n289\\t\\n290\\t// ── Database-scoped access control (US-038, FEAT-014) ────────────────────────\\n291\\t\\n292\\t/// A grant that scopes a role to a specific database.\\n293\\t///\\n294\\t/// Without a grant, users cannot access a database (unless they have a\\n295\\t/// wildcard `*` grant or admin role).\\n296\\t#[derive(Debug, Clone, PartialEq, Eq, Serialize, Deserialize)]\\n297\\tpub struct DatabaseGrant {\\n298\\t    /// The actor (user/node) this grant applies to. `\\\"*\\\"` means all users.\\n299\\t    pub actor: String,\\n300\\t    /// The database name. `\\\"*\\\"` means all databases.\\n301\\t    pub database: String,\\n302\\t    /// The role granted for this database.\\n303\\t    pub role: Role,\\n304\\t}\\n305\\t\\n306\\t/// Registry of database-scoped grants.\\n307\\t#[derive(Debug, Clone, Default, Serialize, Deserialize)]\\n308\\tpub struct GrantRegistry {\\n309\\t    grants: Vec\u003cDatabaseGrant\u003e,\\n310\\t}\\n311\\t\\n312\\timpl GrantRegistry {\\n313\\t    /// Create a new empty grant registry.\\n314\\t    pub fn new() -\u003e Self {\\n315\\t        Self::default()\\n316\\t    }\\n317\\t\\n318\\t    /// Add a grant.\\n319\\t    pub fn add(\u0026mut self, grant: DatabaseGrant) {\\n320\\t        self.grants.push(grant);\\n321\\t    }\\n322\\t\\n323\\t    /// Remove all grants for an actor on a database.\\n324\\t    pub fn revoke(\u0026mut self, actor: \u0026str, database: \u0026str) {\\n325\\t        self.grants\\n326\\t            .retain(|g| g.actor != actor || g.database != database);\\n327\\t    }\\n328\\t\\n329\\t    /// Resolve the effective role for an actor on a database.\\n330\\t    ///\\n331\\t    /// Checks grants in order: exact match, then wildcard actor, then\\n332\\t    /// wildcard database. Returns the highest-privilege matching role.\\n333\\t    pub fn effective_role(\u0026self, actor: \u0026str, database: \u0026str) -\u003e Role {\\n334\\t        self.grants\\n335\\t            .iter()\\n336\\t            .filter(|g| {\\n337\\t                (g.actor == actor || g.actor == \\\"*\\\")\\n338\\t                    \u0026\u0026 (g.database == database || g.database == \\\"*\\\")\\n339\\t            })\\n340\\t            .map(|g| g.role)\\n341\\t            .max()\\n342\\t            .unwrap_or(Role::None)\\n343\\t    }\\n344\\t\\n345\\t    /// Check if an actor can perform an operation on a database.\\n346\\t    pub fn check(\\n347\\t        \u0026self,\\n348\\t        actor: \u0026str,\\n349\\t        database: \u0026str,\\n350\\t        operation: Operation,\\n351\\t    ) -\u003e Result\u003c(), AxonError\u003e {\\n352\\t        let role = self.effective_role(actor, database);\\n353\\t        if role \u003e= operation.required_role() {\\n354\\t            Ok(())\\n355\\t        } else {\\n356\\t            Err(AxonError::InvalidOperation(format!(\\n357\\t                \\\"no grant for actor '{actor}' on database '{database}' with sufficient role (has '{role}', needs '{}')\\\",\\n358\\t                operation.required_role()\\n359\\t            )))\\n360\\t        }\\n361\\t    }\\n362\\t\\n363\\t    /// List all grants.\\n364\\t    pub fn list(\u0026self) -\u003e \u0026[DatabaseGrant] {\\n365\\t        \u0026self.grants\\n366\\t    }\\n367\\t}\\n368\\t\\n369\\t#[cfg(test)]\\n370\\tmod tests {\\n371\\t    use super::*;\\n372\\t\\n373\\t    #[test]\\n374\\t    fn role_ordering() {\\n375\\t        assert!(Role::Admin \u003e Role::Write);\\n376\\t        assert!(Role::Write \u003e Role::Read);\\n377\\t        assert!(Role::Read \u003e Role::None);\\n378\\t    }\\n379\\t\\n380\\t    #[test]\\n381\\t    fn role_from_tag() {\\n382\\t        // Primary tags\\n383\\t        assert_eq!(Role::from_tag(\\\"tag:axon-admin\\\"), Role::Admin);\\n384\\t        assert_eq!(Role::from_tag(\\\"tag:axon-write\\\"), Role::Write);\\n385\\t        assert_eq!(Role::from_tag(\\\"tag:axon-read\\\"), Role::Read);\\n386\\t        // Short-form aliases\\n387\\t        assert_eq!(Role::from_tag(\\\"tag:admin\\\"), Role::Admin);\\n388\\t        assert_eq!(Role::from_tag(\\\"tag:write\\\"), Role::Write);\\n389\\t        assert_eq!(Role::from_tag(\\\"tag:read\\\"), Role::Read);\\n390\\t        // Bare names (no tag: prefix)\\n391\\t        assert_eq!(Role::from_tag(\\\"admin\\\"), Role::Admin);\\n392\\t        assert_eq!(Role::from_tag(\\\"write\\\"), Role::Write);\\n393\\t        assert_eq!(Role::from_tag(\\\"read\\\"), Role::Read);\\n394\\t        // Agent alias\\n395\\t        assert_eq!(Role::from_tag(\\\"tag:axon-agent\\\"), Role::Write);\\n396\\t        // Unknown\\n397\\t        assert_eq!(Role::from_tag(\\\"unknown\\\"), Role::None);\\n398\\t    }\\n399\\t\"}]},\"parent_tool_use_id\":\"toolu_01TSMSYvQzdh78YH3Sxyiy8q\",\"session_id\":\"80f0eb9d-4064-4d06-8560-e247ce1170f2\",\"uuid\":\"7ede5a95-a576-4691-a591-d02b7bdc8f8e\",\"timestamp\":\"2026-04-15T01:31:05.922Z\"}\n{\"type\":\"system\",\"subtype\":\"task_progress\",\"task_id\":\"ab7893c6e8bebbea1\",\"tool_use_id\":\"toolu_01TSMSYvQzdh78YH3Sxyiy8q\",\"description\":\"Reading crates/axon-core/src/auth.rs\",\"usage\":{\"total_tokens\":30023,\"tool_uses\":21,\"duration_ms\":15717},\"last_tool_name\":\"Read\",\"uuid\":\"e2cab029-1f81-46c8-adac-19446344cd8e\",\"session_id\":\"80f0eb9d-4064-4d06-8560-e247ce1170f2\"}\n{\"type\":\"assistant\",\"message\":{\"model\":\"claude-haiku-4-5-20251001\",\"id\":\"msg_011SNRZDMg65PuYWAEQgKe6a\",\"type\":\"message\",\"role\":\"assistant\",\"content\":[{\"type\":\"tool_use\",\"id\":\"toolu_017GHCJLm7sSs2NeYW5LxZ8x\",\"name\":\"Read\",\"input\":{\"file_path\":\"/tmp/ddx-exec-wt/.execute-bead-wt-axon-dccbdf73-20260415T013041-1340da9f/crates/axon-core/src/auth.rs\",\"offset\":900,\"limit\":500},\"caller\":{\"type\":\"direct\"}}],\"stop_reason\":null,\"stop_sequence\":null,\"stop_details\":null,\"usage\":{\"input_tokens\":6,\"cache_creation_input_tokens\":567,\"cache_read_input_tokens\":29402,\"cache_creation\":{\"ephemeral_5m_input_tokens\":567,\"ephemeral_1h_input_tokens\":0},\"output_tokens\":1,\"service_tier\":\"standard\",\"inference_geo\":\"not_available\"},\"context_management\":null},\"parent_tool_use_id\":\"toolu_01TSMSYvQzdh78YH3Sxyiy8q\",\"session_id\":\"80f0eb9d-4064-4d06-8560-e247ce1170f2\",\"uuid\":\"40244f86-4c2c-40ec-9f93-a0b53ec28e7a\"}\n{\"type\":\"user\",\"message\":{\"role\":\"user\",\"content\":[{\"tool_use_id\":\"toolu_017xXnEF67K9wcoU5PYR97aD\",\"type\":\"tool_result\",\"content\":\"400\\t\\n401\\t    #[test]\\n402\\t    fn role_from_tags_picks_highest() {\\n403\\t        let tags = vec![\\\"tag:axon-read\\\".into(), \\\"tag:axon-write\\\".into()];\\n404\\t        assert_eq!(Role::from_tags(\u0026tags), Role::Write);\\n405\\t    }\\n406\\t\\n407\\t    #[test]\\n408\\t    fn role_from_empty_tags() {\\n409\\t        assert_eq!(Role::from_tags(\u0026[]), Role::None);\\n410\\t    }\\n411\\t\\n412\\t    #[test]\\n413\\t    fn anonymous_has_admin() {\\n414\\t        let id = CallerIdentity::anonymous();\\n415\\t        assert_eq!(id.role, Role::Admin);\\n416\\t        assert_eq!(id.actor, \\\"anonymous\\\");\\n417\\t    }\\n418\\t\\n419\\t    #[test]\\n420\\t    fn admin_can_do_everything() {\\n421\\t        let admin = CallerIdentity::new(\\\"alice\\\", Role::Admin);\\n422\\t        assert!(admin.check(Operation::Read).is_ok());\\n423\\t        assert!(admin.check(Operation::Write).is_ok());\\n424\\t        assert!(admin.check(Operation::Admin).is_ok());\\n425\\t    }\\n426\\t\\n427\\t    #[test]\\n428\\t    fn write_can_read_and_write_but_not_admin() {\\n429\\t        let writer = CallerIdentity::new(\\\"bob\\\", Role::Write);\\n430\\t        assert!(writer.check(Operation::Read).is_ok());\\n431\\t        assert!(writer.check(Operation::Write).is_ok());\\n432\\t        assert!(writer.check(Operation::Admin).is_err());\\n433\\t    }\\n434\\t\\n435\\t    #[test]\\n436\\t    fn read_can_only_read() {\\n437\\t        let reader = CallerIdentity::new(\\\"charlie\\\", Role::Read);\\n438\\t        assert!(reader.check(Operation::Read).is_ok());\\n439\\t        assert!(reader.check(Operation::Write).is_err());\\n440\\t        assert!(reader.check(Operation::Admin).is_err());\\n441\\t    }\\n442\\t\\n443\\t    #[test]\\n444\\t    fn none_cannot_do_anything() {\\n445\\t        let nobody = CallerIdentity::new(\\\"nobody\\\", Role::None);\\n446\\t        assert!(nobody.check(Operation::Read).is_err());\\n447\\t        assert!(nobody.check(Operation::Write).is_err());\\n448\\t        assert!(nobody.check(Operation::Admin).is_err());\\n449\\t    }\\n450\\t\\n451\\t    #[test]\\n452\\t    fn write_denied_error_is_descriptive() {\\n453\\t        let reader = CallerIdentity::new(\\\"charlie\\\", Role::Read);\\n454\\t        let err = reader\\n455\\t            .check(Operation::Write)\\n456\\t            .expect_err(\\\"read role should not be allowed to write\\\");\\n457\\t        let msg = err.to_string();\\n458\\t        assert!(msg.contains(\\\"permission denied\\\"), \\\"msg: {msg}\\\");\\n459\\t        assert!(msg.contains(\\\"read\\\"), \\\"msg: {msg}\\\");\\n460\\t        assert!(msg.contains(\\\"write\\\"), \\\"msg: {msg}\\\");\\n461\\t    }\\n462\\t\\n463\\t    // ── Field-level masking tests (US-046) ──────────────────────────────\\n464\\t\\n465\\t    #[test]\\n466\\t    fn admin_sees_all_fields() {\\n467\\t        let admin = CallerIdentity::new(\\\"admin\\\", Role::Admin);\\n468\\t        let mut data = serde_json::json!({\\\"name\\\": \\\"Alice\\\", \\\"salary\\\": 100000});\\n469\\t        let policies = vec![MaskPolicy {\\n470\\t            field: \\\"salary\\\".into(),\\n471\\t            min_role: Role::Admin,\\n472\\t        }];\\n473\\t        admin.apply_masks(\u0026mut data, \u0026policies);\\n474\\t        assert!(data.get(\\\"salary\\\").is_some(), \\\"admin should see salary\\\");\\n475\\t    }\\n476\\t\\n477\\t    #[test]\\n478\\t    fn reader_cannot_see_admin_only_fields() {\\n479\\t        let reader = CallerIdentity::new(\\\"bob\\\", Role::Read);\\n480\\t        let mut data =\\n481\\t            serde_json::json!({\\\"name\\\": \\\"Alice\\\", \\\"salary\\\": 100000, \\\"email\\\": \\\"alice@co.com\\\"});\\n482\\t        let policies = vec![MaskPolicy {\\n483\\t            field: \\\"salary\\\".into(),\\n484\\t            min_role: Role::Admin,\\n485\\t        }];\\n486\\t        reader.apply_masks(\u0026mut data, \u0026policies);\\n487\\t        assert!(data.get(\\\"salary\\\").is_none(), \\\"reader should not see salary\\\");\\n488\\t        assert!(data.get(\\\"name\\\").is_some(), \\\"name is not masked\\\");\\n489\\t        assert!(data.get(\\\"email\\\").is_some(), \\\"email is not masked\\\");\\n490\\t    }\\n491\\t\\n492\\t    #[test]\\n493\\t    fn writer_sees_write_level_fields() {\\n494\\t        let writer = CallerIdentity::new(\\\"charlie\\\", Role::Write);\\n495\\t        let mut data = serde_json::json!({\\\"name\\\": \\\"Alice\\\", \\\"internal_notes\\\": \\\"sensitive\\\"});\\n496\\t        let policies = vec![MaskPolicy {\\n497\\t            field: \\\"internal_notes\\\".into(),\\n498\\t            min_role: Role::Write,\\n499\\t        }];\\n500\\t        writer.apply_masks(\u0026mut data, \u0026policies);\\n501\\t        assert!(\\n502\\t            data.get(\\\"internal_notes\\\").is_some(),\\n503\\t            \\\"writer should see write-level fields\\\"\\n504\\t        );\\n505\\t    }\\n506\\t\\n507\\t    #[test]\\n508\\t    fn reader_cannot_see_write_level_fields() {\\n509\\t        let reader = CallerIdentity::new(\\\"dave\\\", Role::Read);\\n510\\t        let mut data = serde_json::json!({\\\"name\\\": \\\"Alice\\\", \\\"internal_notes\\\": \\\"sensitive\\\"});\\n511\\t        let policies = vec![MaskPolicy {\\n512\\t            field: \\\"internal_notes\\\".into(),\\n513\\t            min_role: Role::Write,\\n514\\t        }];\\n515\\t        reader.apply_masks(\u0026mut data, \u0026policies);\\n516\\t        assert!(\\n517\\t            data.get(\\\"internal_notes\\\").is_none(),\\n518\\t            \\\"reader should not see write-level fields\\\"\\n519\\t        );\\n520\\t    }\\n521\\t\\n522\\t    #[test]\\n523\\t    fn multiple_mask_policies() {\\n524\\t        let reader = CallerIdentity::new(\\\"eve\\\", Role::Read);\\n525\\t        let mut data = serde_json::json!({\\\"name\\\": \\\"Alice\\\", \\\"salary\\\": 100000, \\\"ssn\\\": \\\"123-45-6789\\\"});\\n526\\t        let policies = vec![\\n527\\t            MaskPolicy {\\n528\\t                field: \\\"salary\\\".into(),\\n529\\t                min_role: Role::Admin,\\n530\\t            },\\n531\\t            MaskPolicy {\\n532\\t                field: \\\"ssn\\\".into(),\\n533\\t                min_role: Role::Write,\\n534\\t            },\\n535\\t        ];\\n536\\t        reader.apply_masks(\u0026mut data, \u0026policies);\\n537\\t        assert!(data.get(\\\"salary\\\").is_none());\\n538\\t        assert!(data.get(\\\"ssn\\\").is_none());\\n539\\t        assert!(data.get(\\\"name\\\").is_some());\\n540\\t    }\\n541\\t\\n542\\t    #[test]\\n543\\t    fn mask_on_non_object_is_noop() {\\n544\\t        let reader = CallerIdentity::new(\\\"f\\\", Role::Read);\\n545\\t        let mut data = serde_json::json!(\\\"just a string\\\");\\n546\\t        let policies = vec![MaskPolicy {\\n547\\t            field: \\\"anything\\\".into(),\\n548\\t            min_role: Role::Admin,\\n549\\t        }];\\n550\\t        reader.apply_masks(\u0026mut data, \u0026policies);\\n551\\t        assert_eq!(data, serde_json::json!(\\\"just a string\\\"));\\n552\\t    }\\n553\\t\\n554\\t    // ── ABAC write policy tests (US-047) ───────────────────────────────\\n555\\t\\n556\\t    #[test]\\n557\\t    fn write_policy_allows_matching_role() {\\n558\\t        let policy = WritePolicy {\\n559\\t            collection: \\\"tasks\\\".into(),\\n560\\t            min_write_role: Role::Write,\\n561\\t            immutable_fields: vec![],\\n562\\t        };\\n563\\t        let caller = CallerIdentity::new(\\\"alice\\\", Role::Write);\\n564\\t        assert!(policy.check_write(\u0026caller).is_ok());\\n565\\t    }\\n566\\t\\n567\\t    #[test]\\n568\\t    fn write_policy_denies_insufficient_role() {\\n569\\t        let policy = WritePolicy {\\n570\\t            collection: \\\"tasks\\\".into(),\\n571\\t            min_write_role: Role::Admin,\\n572\\t            immutable_fields: vec![],\\n573\\t        };\\n574\\t        let caller = CallerIdentity::new(\\\"bob\\\", Role::Write);\\n575\\t        assert!(policy.check_write(\u0026caller).is_err());\\n576\\t    }\\n577\\t\\n578\\t    #[test]\\n579\\t    fn immutable_fields_detected() {\\n580\\t        let policy = WritePolicy {\\n581\\t            collection: \\\"tasks\\\".into(),\\n582\\t            min_write_role: Role::Write,\\n583\\t            immutable_fields: vec![\\\"created_by\\\".into(), \\\"source\\\".into()],\\n584\\t        };\\n585\\t\\n586\\t        let old_data = serde_json::json!({\\\"title\\\": \\\"T\\\", \\\"created_by\\\": \\\"alice\\\", \\\"source\\\": \\\"api\\\"});\\n587\\t        let new_data = serde_json::json!({\\\"title\\\": \\\"T2\\\", \\\"created_by\\\": \\\"alice\\\", \\\"source\\\": \\\"api\\\"});\\n588\\t        let violations = policy.check_immutable_fields(\u0026old_data, \u0026new_data);\\n589\\t        assert!(violations.is_empty());\\n590\\t\\n591\\t        let changed = serde_json::json!({\\\"title\\\": \\\"T2\\\", \\\"created_by\\\": \\\"bob\\\", \\\"source\\\": \\\"api\\\"});\\n592\\t        let violations = policy.check_immutable_fields(\u0026old_data, \u0026changed);\\n593\\t        assert_eq!(violations, vec![\\\"created_by\\\"]);\\n594\\t    }\\n595\\t\\n596\\t    #[test]\\n597\\t    fn immutable_field_added_is_ok() {\\n598\\t        // Adding an immutable field to an entity that didn't have it is OK.\\n599\\t        let policy = WritePolicy {\\n600\\t            collection: \\\"tasks\\\".into(),\\n601\\t            min_write_role: Role::Write,\\n602\\t            immutable_fields: vec![\\\"locked\\\".into()],\\n603\\t        };\\n604\\t        let old_data = serde_json::json!({\\\"title\\\": \\\"T\\\"});\\n605\\t        let new_data = serde_json::json!({\\\"title\\\": \\\"T\\\", \\\"locked\\\": true});\\n606\\t        let violations = policy.check_immutable_fields(\u0026old_data, \u0026new_data);\\n607\\t        assert!(violations.is_empty());\\n608\\t    }\\n609\\t\\n610\\t    #[test]\\n611\\t    fn immutable_field_removed_is_violation() {\\n612\\t        let policy = WritePolicy {\\n613\\t            collection: \\\"tasks\\\".into(),\\n614\\t            min_write_role: Role::Write,\\n615\\t            immutable_fields: vec![\\\"source\\\".into()],\\n616\\t        };\\n617\\t        let old_data = serde_json::json!({\\\"title\\\": \\\"T\\\", \\\"source\\\": \\\"api\\\"});\\n618\\t        let new_data = serde_json::json!({\\\"title\\\": \\\"T2\\\"});\\n619\\t        let violations = policy.check_immutable_fields(\u0026old_data, \u0026new_data);\\n620\\t        assert_eq!(violations, vec![\\\"source\\\"]);\\n621\\t    }\\n622\\t\\n623\\t    // ── Database grant tests (US-038) ──────────────────────────────────\\n624\\t\\n625\\t    #[test]\\n626\\t    fn grant_registry_empty_denies_all() {\\n627\\t        let registry = GrantRegistry::new();\\n628\\t        assert_eq!(registry.effective_role(\\\"alice\\\", \\\"prod\\\"), Role::None);\\n629\\t        assert!(registry.check(\\\"alice\\\", \\\"prod\\\", Operation::Read).is_err());\\n630\\t    }\\n631\\t\\n632\\t    #[test]\\n633\\t    fn exact_grant_allows_access() {\\n634\\t        let mut registry = GrantRegistry::new();\\n635\\t        registry.add(DatabaseGrant {\\n636\\t            actor: \\\"alice\\\".into(),\\n637\\t            database: \\\"prod\\\".into(),\\n638\\t            role: Role::Write,\\n639\\t        });\\n640\\t        assert_eq!(registry.effective_role(\\\"alice\\\", \\\"prod\\\"), Role::Write);\\n641\\t        assert!(registry.check(\\\"alice\\\", \\\"prod\\\", Operation::Write).is_ok());\\n642\\t        assert!(registry.check(\\\"alice\\\", \\\"prod\\\", Operation::Admin).is_err());\\n643\\t    }\\n644\\t\\n645\\t    #[test]\\n646\\t    fn wildcard_actor_grant() {\\n647\\t        let mut registry = GrantRegistry::new();\\n648\\t        registry.add(DatabaseGrant {\\n649\\t            actor: \\\"*\\\".into(),\\n650\\t            database: \\\"public\\\".into(),\\n651\\t            role: Role::Read,\\n652\\t        });\\n653\\t        assert_eq!(registry.effective_role(\\\"anyone\\\", \\\"public\\\"), Role::Read);\\n654\\t        assert_eq!(registry.effective_role(\\\"alice\\\", \\\"public\\\"), Role::Read);\\n655\\t    }\\n656\\t\\n657\\t    #[test]\\n658\\t    fn wildcard_database_grant() {\\n659\\t        let mut registry = GrantRegistry::new();\\n660\\t        registry.add(DatabaseGrant {\\n661\\t            actor: \\\"admin-bot\\\".into(),\\n662\\t            database: \\\"*\\\".into(),\\n663\\t            role: Role::Admin,\\n664\\t        });\\n665\\t        assert_eq!(\\n666\\t            registry.effective_role(\\\"admin-bot\\\", \\\"any-database\\\"),\\n667\\t            Role::Admin\\n668\\t        );\\n669\\t    }\\n670\\t\\n671\\t    #[test]\\n672\\t    fn highest_privilege_wins() {\\n673\\t        let mut registry = GrantRegistry::new();\\n674\\t        registry.add(DatabaseGrant {\\n675\\t            actor: \\\"alice\\\".into(),\\n676\\t            database: \\\"prod\\\".into(),\\n677\\t            role: Role::Read,\\n678\\t        });\\n679\\t        registry.add(DatabaseGrant {\\n680\\t            actor: \\\"alice\\\".into(),\\n681\\t            database: \\\"prod\\\".into(),\\n682\\t            role: Role::Admin,\\n683\\t        });\\n684\\t        assert_eq!(registry.effective_role(\\\"alice\\\", \\\"prod\\\"), Role::Admin);\\n685\\t    }\\n686\\t\\n687\\t    #[test]\\n688\\t    fn no_cross_database_access_without_grant() {\\n689\\t        let mut registry = GrantRegistry::new();\\n690\\t        registry.add(DatabaseGrant {\\n691\\t            actor: \\\"alice\\\".into(),\\n692\\t            database: \\\"dev\\\".into(),\\n693\\t            role: Role::Admin,\\n694\\t        });\\n695\\t        // alice has no grant on prod\\n696\\t        assert_eq!(registry.effective_role(\\\"alice\\\", \\\"prod\\\"), Role::None);\\n697\\t    }\\n698\\t\\n699\\t    #[test]\\n700\\t    fn revoke_removes_grants() {\\n701\\t        let mut registry = GrantRegistry::new();\\n702\\t        registry.add(DatabaseGrant {\\n703\\t            actor: \\\"alice\\\".into(),\\n704\\t            database: \\\"prod\\\".into(),\\n705\\t            role: Role::Write,\\n706\\t        });\\n707\\t        registry.revoke(\\\"alice\\\", \\\"prod\\\");\\n708\\t        assert_eq!(registry.effective_role(\\\"alice\\\", \\\"prod\\\"), Role::None);\\n709\\t    }\\n710\\t}\\n711\\t\\n712\\t// ── ADR-018: Tenant/User/Credential types ───────────────────────────────────\\n713\\t\\n714\\tuse uuid::Uuid;\\n715\\t\\n716\\t/// Stable identifier for a tenant.\\n717\\t#[derive(Debug, Clone, PartialEq, Eq, Hash, Serialize, Deserialize)]\\n718\\t#[serde(transparent)]\\n719\\tpub struct TenantId(pub String);\\n720\\t\\n721\\timpl TenantId {\\n722\\t    /// Generate a fresh tenant id (UUIDv7 string).\\n723\\t    pub fn generate() -\u003e Self {\\n724\\t        Self(Uuid::now_v7().to_string())\\n725\\t    }\\n726\\t\\n727\\t    /// Wrap an existing id string.\\n728\\t    pub fn new(id: impl Into\u003cString\u003e) -\u003e Self {\\n729\\t        Self(id.into())\\n730\\t    }\\n731\\t\\n732\\t    pub fn as_str(\u0026self) -\u003e \u0026str {\\n733\\t        \u0026self.0\\n734\\t    }\\n735\\t}\\n736\\t\\n737\\timpl std::fmt::Display for TenantId {\\n738\\t    fn fmt(\u0026self, f: \u0026mut std::fmt::Formatter\u003c'_\u003e) -\u003e std::fmt::Result {\\n739\\t        write!(f, \\\"{}\\\", self.0)\\n740\\t    }\\n741\\t}\\n742\\t\\n743\\t/// Stable identifier for a user.\\n744\\t#[derive(Debug, Clone, PartialEq, Eq, Hash, Serialize, Deserialize)]\\n745\\t#[serde(transparent)]\\n746\\tpub struct UserId(pub String);\\n747\\t\\n748\\timpl UserId {\\n749\\t    /// Generate a fresh user id (UUIDv7 string).\\n750\\t    pub fn generate() -\u003e Self {\\n751\\t        Self(Uuid::now_v7().to_string())\\n752\\t    }\\n753\\t\\n754\\t    /// Wrap an existing id string.\\n755\\t    pub fn new(id: impl Into\u003cString\u003e) -\u003e Self {\\n756\\t        Self(id.into())\\n757\\t    }\\n758\\t\\n759\\t    pub fn as_str(\u0026self) -\u003e \u0026str {\\n760\\t        \u0026self.0\\n761\\t    }\\n762\\t}\\n763\\t\\n764\\timpl std::fmt::Display for UserId {\\n765\\t    fn fmt(\u0026self, f: \u0026mut std::fmt::Formatter\u003c'_\u003e) -\u003e std::fmt::Result {\\n766\\t        write!(f, \\\"{}\\\", self.0)\\n767\\t    }\\n768\\t}\\n769\\t\\n770\\t/// A tenant (global account boundary).\\n771\\t#[derive(Debug, Clone, PartialEq, Serialize, Deserialize)]\\n772\\tpub struct Tenant {\\n773\\t    pub id: TenantId,\\n774\\t    pub name: String,\\n775\\t    pub created_at_ms: u64,\\n776\\t}\\n777\\t\\n778\\t/// A user (global identity).\\n779\\t#[derive(Debug, Clone, PartialEq, Serialize, Deserialize)]\\n780\\tpub struct User {\\n781\\t    pub id: UserId,\\n782\\t    pub display_name: String,\\n783\\t    #[serde(default, skip_serializing_if = \\\"Option::is_none\\\")]\\n784\\t    pub email: Option\u003cString\u003e,\\n785\\t    pub created_at_ms: u64,\\n786\\t    #[serde(default, skip_serializing_if = \\\"Option::is_none\\\")]\\n787\\t    pub suspended_at_ms: Option\u003cu64\u003e,\\n788\\t}\\n789\\t\\n790\\t/// External identity that federates to a user.\\n791\\t#[derive(Debug, Clone, PartialEq, Serialize, Deserialize)]\\n792\\tpub struct UserIdentity {\\n793\\t    pub provider: String,\\n794\\t    pub external_id: String,\\n795\\t    pub user_id: UserId,\\n796\\t}\\n797\\t\\n798\\t/// A user's membership in a tenant.\\n799\\t#[derive(Debug, Clone, PartialEq, Serialize, Deserialize)]\\n800\\tpub struct TenantMember {\\n801\\t    pub tenant_id: TenantId,\\n802\\t    pub user_id: UserId,\\n803\\t    pub role: TenantRole,\\n804\\t}\\n805\\t\\n806\\t/// Role a user has within a tenant.\\n807\\t#[derive(Debug, Clone, PartialEq, Eq, PartialOrd, Ord, Hash, Serialize, Deserialize)]\\n808\\tpub enum TenantRole {\\n809\\t    Admin,\\n810\\t    Write,\\n811\\t    Read,\\n812\\t}\\n813\\t\\n814\\timpl TenantRole {\\n815\\t    /// Returns the operations this role can delegate (ceiling).\\n816\\t    ///\\n817\\t    /// - `Admin` → `{Read, Write, Admin}`\\n818\\t    /// - `Write` → `{Read, Write}`\\n819\\t    /// - `Read` → `{Read}`\\n820\\t    pub fn delegation_ops(\u0026self) -\u003e Vec\u003cOp\u003e {\\n821\\t        match self {\\n822\\t            TenantRole::Admin =\u003e vec![Op::Read, Op::Write, Op::Admin],\\n823\\t            TenantRole::Write =\u003e vec![Op::Read, Op::Write],\\n824\\t            TenantRole::Read =\u003e vec![Op::Read],\\n825\\t        }\\n826\\t    }\\n827\\t}\\n828\\t\\n829\\t/// An operation that can be granted.\\n830\\t#[derive(Debug, Clone, PartialEq, Eq, Hash, Serialize, Deserialize)]\\n831\\tpub enum Op {\\n832\\t    Read,\\n833\\t    Write,\\n834\\t    Admin,\\n835\\t}\\n836\\t\\n837\\t/// A database with a set of granted operations.\\n838\\t#[derive(Debug, Clone, PartialEq, Serialize, Deserialize)]\\n839\\tpub struct GrantedDatabase {\\n840\\t    pub name: String,\\n841\\t    pub ops: Vec\u003cOp\u003e,\\n842\\t}\\n843\\t\\n844\\t/// A collection of database grants.\\n845\\t#[derive(Debug, Clone, PartialEq, Serialize, Deserialize)]\\n846\\tpub struct Grants {\\n847\\t    pub databases: Vec\u003cGrantedDatabase\u003e,\\n848\\t}\\n849\\t\\n850\\timpl Grants {\\n851\\t    /// Validate the grants structure according to the v5 schema.\\n852\\t    ///\\n853\\t    /// - At most 1024 databases\\n854\\t    /// - Each database must have at least one op\\n855\\t    /// - Each op must be unique (no duplicates)\\n856\\t    pub fn validate(\u0026self) -\u003e Result\u003c(), AuthError\u003e {\\n857\\t        if self.databases.len() \u003e 1024 {\\n858\\t            return Err(AuthError::GrantsMalformed);\\n859\\t        }\\n860\\t        for db in \u0026self.databases {\\n861\\t            db.validate()?;\\n862\\t        }\\n863\\t        Ok(())\\n864\\t    }\\n865\\t}\\n866\\t\\n867\\timpl GrantedDatabase {\\n868\\t    /// Validate a single granted database.\\n869\\t    ///\\n870\\t    /// - name must be non-empty\\n871\\t    /// - ops must not be empty\\n872\\t    /// - ops must be unique\\n873\\t    pub fn validate(\u0026self) -\u003e Result\u003c(), AuthError\u003e {\\n874\\t        if self.name.is_empty() {\\n875\\t            return Err(AuthError::GrantsMalformed);\\n876\\t        }\\n877\\t        if self.ops.is_empty() {\\n878\\t            return Err(AuthError::GrantsMalformed);\\n879\\t        }\\n880\\t        // Check for duplicate ops\\n881\\t        let unique_ops: std::collections::HashSet\u003c_\u003e = self.ops.iter().collect();\\n882\\t        if unique_ops.len() != self.ops.len() {\\n883\\t            return Err(AuthError::GrantsMalformed);\\n884\\t        }\\n885\\t        Ok(())\\n886\\t    }\\n887\\t}\\n888\\t\\n889\\t/// JWT claims for tenant-scoped credentials (ADR-018 §4).\\n890\\t#[derive(Debug, Clone, PartialEq, Serialize, Deserialize)]\\n891\\tpub struct JwtClaims {\\n892\\t    pub iss: String,\\n893\\t    pub sub: String,\\n894\\t    pub aud: String,\\n895\\t    pub jti: String,\\n896\\t    pub iat: u64,\\n897\\t    pub nbf: u64,\\n898\\t    pub exp: u64,\\n899\\t    pub grants: Grants,\"}]},\"parent_tool_use_id\":\"toolu_01TSMSYvQzdh78YH3Sxyiy8q\",\"session_id\":\"80f0eb9d-4064-4d06-8560-e247ce1170f2\",\"uuid\":\"2d11be8a-1054-47c1-b2e6-60ab6bd947cf\",\"timestamp\":\"2026-04-15T01:31:06.078Z\"}\n{\"type\":\"user\",\"message\":{\"role\":\"user\",\"content\":[{\"tool_use_id\":\"toolu_017GHCJLm7sSs2NeYW5LxZ8x\",\"type\":\"tool_result\",\"content\":\"900\\t}\\n901\\t\\n902\\timpl JwtClaims {\\n903\\t    /// Validate the JWT claims structure.\\n904\\t    ///\\n905\\t    /// Returns `AuthError::CredentialMalformed` if:\\n906\\t    /// - `aud` is not a single string (e.g., it was a JSON array)\\n907\\t    /// - Grants don't match the expected schema\\n908\\t    ///\\n909\\t    /// This is typically used after deserialization to catch schema violations\\n910\\t    /// that serde doesn't catch by itself (e.g., aud as an array).\\n911\\t    pub fn validate(\u0026self) -\u003e Result\u003c(), AuthError\u003e {\\n912\\t        // Check grants structure\\n913\\t        self.grants.validate()?;\\n914\\t        Ok(())\\n915\\t    }\\n916\\t}\\n917\\t\\n918\\t/// Authentication error variants (ADR-018 §4 failure-mode table).\\n919\\t///\\n920\\t/// This enum has exactly 14 variants matching the failure modes in\\n921\\t/// ADR-018 §4 \\\"JWT failure mode → HTTP status + error code\\\".\\n922\\t#[derive(Debug, Clone, PartialEq, Eq, Serialize, Deserialize)]\\n923\\tpub enum AuthError {\\n924\\t    /// No `Authorization` header (non-`--no-auth` mode).\\n925\\t    Unauthenticated,\\n926\\t\\n927\\t    /// Header present but not `Bearer \u003ctoken\u003e`, or JWT structurally invalid,\\n928\\t    /// or `aud` claim is a JSON array instead of a string.\\n929\\t    CredentialMalformed,\\n930\\t\\n931\\t    /// Signature invalid (wrong key or tampered payload).\\n932\\t    CredentialInvalid,\\n933\\t\\n934\\t    /// `exp` claim is in the past.\\n935\\t    CredentialExpired,\\n936\\t\\n937\\t    /// `nbf` claim is in the future.\\n938\\t    CredentialNotYetValid,\\n939\\t\\n940\\t    /// `jti` claim is present in the revocation list.\\n941\\t    CredentialRevoked,\\n942\\t\\n943\\t    /// `iss` claim does not match this deployment's issuer.\\n944\\t    CredentialForeignIssuer,\\n945\\t\\n946\\t    /// `aud` claim does not match the tenant in the URL path.\\n947\\t    CredentialWrongTenant,\\n948\\t\\n949\\t    /// `sub` claim resolves to a suspended or deleted user.\\n950\\t    UserSuspended,\\n951\\t\\n952\\t    /// `sub` claim is not a member of the tenant in the URL path.\\n953\\t    NotATenantMember,\\n954\\t\\n955\\t    /// URL `{database}` segment not found in `grants.databases[]`.\\n956\\t    DatabaseNotGranted,\\n957\\t\\n958\\t    /// Required operation not in the matching grant's `ops[]`.\\n959\\t    OpNotGranted,\\n960\\t\\n961\\t    /// Grant scope exceeds issuer's role at issuance time.\\n962\\t    GrantsExceedIssuerRole,\\n963\\t\\n964\\t    /// Malformed grants payload (schema validation failure).\\n965\\t    GrantsMalformed,\\n966\\t}\\n967\\t\\n968\\timpl std::fmt::Display for AuthError {\\n969\\t    fn fmt(\u0026self, f: \u0026mut std::fmt::Formatter\u003c'_\u003e) -\u003e std::fmt::Result {\\n970\\t        match self {\\n971\\t            AuthError::Unauthenticated =\u003e write!(f, \\\"unauthenticated\\\"),\\n972\\t            AuthError::CredentialMalformed =\u003e write!(f, \\\"credential malformed\\\"),\\n973\\t            AuthError::CredentialInvalid =\u003e write!(f, \\\"credential invalid\\\"),\\n974\\t            AuthError::CredentialExpired =\u003e write!(f, \\\"credential expired\\\"),\\n975\\t            AuthError::CredentialNotYetValid =\u003e write!(f, \\\"credential not yet valid\\\"),\\n976\\t            AuthError::CredentialRevoked =\u003e write!(f, \\\"credential revoked\\\"),\\n977\\t            AuthError::CredentialForeignIssuer =\u003e write!(f, \\\"credential foreign issuer\\\"),\\n978\\t            AuthError::CredentialWrongTenant =\u003e write!(f, \\\"credential wrong tenant\\\"),\\n979\\t            AuthError::UserSuspended =\u003e write!(f, \\\"user suspended\\\"),\\n980\\t            AuthError::NotATenantMember =\u003e write!(f, \\\"not a tenant member\\\"),\\n981\\t            AuthError::DatabaseNotGranted =\u003e write!(f, \\\"database not granted\\\"),\\n982\\t            AuthError::OpNotGranted =\u003e write!(f, \\\"op not granted\\\"),\\n983\\t            AuthError::GrantsExceedIssuerRole =\u003e write!(f, \\\"grants exceed issuer role\\\"),\\n984\\t            AuthError::GrantsMalformed =\u003e write!(f, \\\"grants malformed\\\"),\\n985\\t        }\\n986\\t    }\\n987\\t}\\n988\\t\\n989\\timpl std::error::Error for AuthError {}\\n990\\t\\n991\\timpl From\u003cserde_json::Error\u003e for AuthError {\\n992\\t    fn from(_: serde_json::Error) -\u003e Self {\\n993\\t        AuthError::CredentialMalformed\\n994\\t    }\\n995\\t}\\n996\\t\\n997\\t/// Parse a JSON string into [`JwtClaims`], mapping any deserialization error\\n998\\t/// to [`AuthError::CredentialMalformed`].\\n999\\tpub fn parse_claims(s: \u0026str) -\u003e Result\u003cJwtClaims, AuthError\u003e {\\n1000\\t    serde_json::from_str(s).map_err(AuthError::from)\\n1001\\t}\\n1002\\t\\n1003\\t/// Compile-time exhaustive check that `AuthError` has exactly 14 variants\\n1004\\t/// (ADR-018 §4). Adding or removing a variant without updating this match\\n1005\\t/// will cause a compile error.\\n1006\\tconst _: () = {\\n1007\\t    const fn _exhaustive_variant_check(e: \u0026AuthError) -\u003e usize {\\n1008\\t        match e {\\n1009\\t            AuthError::Unauthenticated =\u003e 0,\\n1010\\t            AuthError::CredentialMalformed =\u003e 1,\\n1011\\t            AuthError::CredentialInvalid =\u003e 2,\\n1012\\t            AuthError::CredentialExpired =\u003e 3,\\n1013\\t            AuthError::CredentialNotYetValid =\u003e 4,\\n1014\\t            AuthError::CredentialRevoked =\u003e 5,\\n1015\\t            AuthError::CredentialForeignIssuer =\u003e 6,\\n1016\\t            AuthError::CredentialWrongTenant =\u003e 7,\\n1017\\t            AuthError::UserSuspended =\u003e 8,\\n1018\\t            AuthError::NotATenantMember =\u003e 9,\\n1019\\t            AuthError::DatabaseNotGranted =\u003e 10,\\n1020\\t            AuthError::OpNotGranted =\u003e 11,\\n1021\\t            AuthError::GrantsExceedIssuerRole =\u003e 12,\\n1022\\t            AuthError::GrantsMalformed =\u003e 13,\\n1023\\t        }\\n1024\\t    }\\n1025\\t    // Suppress unused-function lint in const context.\\n1026\\t    let _ = _exhaustive_variant_check;\\n1027\\t};\\n1028\\t\\n1029\\t#[cfg(test)]\\n1030\\tmod auth_core_tests {\\n1031\\t    use super::*;\\n1032\\t\\n1033\\t    // ── Type round-trip tests (Serde) ──────────────────────────────────\\n1034\\t\\n1035\\t    #[test]\\n1036\\t    fn tenant_id_roundtrip() {\\n1037\\t        let id = TenantId::new(\\\"t-123\\\");\\n1038\\t        let json = serde_json::to_string(\u0026id).unwrap();\\n1039\\t        assert_eq!(json, \\\"\\\\\\\"t-123\\\\\\\"\\\");\\n1040\\t        let parsed: TenantId = serde_json::from_str(\u0026json).unwrap();\\n1041\\t        assert_eq!(parsed, id);\\n1042\\t    }\\n1043\\t\\n1044\\t    #[test]\\n1045\\t    fn user_id_roundtrip() {\\n1046\\t        let id = UserId::new(\\\"u-456\\\");\\n1047\\t        let json = serde_json::to_string(\u0026id).unwrap();\\n1048\\t        assert_eq!(json, \\\"\\\\\\\"u-456\\\\\\\"\\\");\\n1049\\t        let parsed: UserId = serde_json::from_str(\u0026json).unwrap();\\n1050\\t        assert_eq!(parsed, id);\\n1051\\t    }\\n1052\\t\\n1053\\t    #[test]\\n1054\\t    fn tenant_roundtrip() {\\n1055\\t        let tenant = Tenant {\\n1056\\t            id: TenantId::new(\\\"t-123\\\"),\\n1057\\t            name: \\\"acme\\\".into(),\\n1058\\t            created_at_ms: 1000,\\n1059\\t        };\\n1060\\t        let json = serde_json::to_string(\u0026tenant).unwrap();\\n1061\\t        let parsed: Tenant = serde_json::from_str(\u0026json).unwrap();\\n1062\\t        assert_eq!(parsed, tenant);\\n1063\\t    }\\n1064\\t\\n1065\\t    #[test]\\n1066\\t    fn user_roundtrip() {\\n1067\\t        let user = User {\\n1068\\t            id: UserId::new(\\\"u-123\\\"),\\n1069\\t            display_name: \\\"Alice\\\".into(),\\n1070\\t            email: Some(\\\"alice@example.com\\\".into()),\\n1071\\t            created_at_ms: 1000,\\n1072\\t            suspended_at_ms: None,\\n1073\\t        };\\n1074\\t        let json = serde_json::to_string(\u0026user).unwrap();\\n1075\\t        let parsed: User = serde_json::from_str(\u0026json).unwrap();\\n1076\\t        assert_eq!(parsed, user);\\n1077\\t    }\\n1078\\t\\n1079\\t    #[test]\\n1080\\t    fn user_without_email_roundtrip() {\\n1081\\t        let user = User {\\n1082\\t            id: UserId::new(\\\"u-123\\\"),\\n1083\\t            display_name: \\\"Bob\\\".into(),\\n1084\\t            email: None,\\n1085\\t            created_at_ms: 1000,\\n1086\\t            suspended_at_ms: None,\\n1087\\t        };\\n1088\\t        let json = serde_json::to_string(\u0026user).unwrap();\\n1089\\t        let parsed: User = serde_json::from_str(\u0026json).unwrap();\\n1090\\t        assert_eq!(parsed, user);\\n1091\\t    }\\n1092\\t\\n1093\\t    #[test]\\n1094\\t    fn user_identity_roundtrip() {\\n1095\\t        let identity = UserIdentity {\\n1096\\t            provider: \\\"tailscale\\\".into(),\\n1097\\t            external_id: \\\"alice@example.com\\\".into(),\\n1098\\t            user_id: UserId::new(\\\"u-123\\\"),\\n1099\\t        };\\n1100\\t        let json = serde_json::to_string(\u0026identity).unwrap();\\n1101\\t        let parsed: UserIdentity = serde_json::from_str(\u0026json).unwrap();\\n1102\\t        assert_eq!(parsed, identity);\\n1103\\t    }\\n1104\\t\\n1105\\t    #[test]\\n1106\\t    fn tenant_member_roundtrip() {\\n1107\\t        let member = TenantMember {\\n1108\\t            tenant_id: TenantId::new(\\\"t-123\\\"),\\n1109\\t            user_id: UserId::new(\\\"u-456\\\"),\\n1110\\t            role: TenantRole::Write,\\n1111\\t        };\\n1112\\t        let json = serde_json::to_string(\u0026member).unwrap();\\n1113\\t        let parsed: TenantMember = serde_json::from_str(\u0026json).unwrap();\\n1114\\t        assert_eq!(parsed, member);\\n1115\\t    }\\n1116\\t\\n1117\\t    #[test]\\n1118\\t    fn tenant_role_roundtrip() {\\n1119\\t        for role in [TenantRole::Admin, TenantRole::Write, TenantRole::Read] {\\n1120\\t            let json = serde_json::to_string(\u0026role).unwrap();\\n1121\\t            let parsed: TenantRole = serde_json::from_str(\u0026json).unwrap();\\n1122\\t            assert_eq!(parsed, role);\\n1123\\t        }\\n1124\\t    }\\n1125\\t\\n1126\\t    #[test]\\n1127\\t    fn op_roundtrip() {\\n1128\\t        for op in [Op::Read, Op::Write, Op::Admin] {\\n1129\\t            let json = serde_json::to_string(\u0026op).unwrap();\\n1130\\t            let parsed: Op = serde_json::from_str(\u0026json).unwrap();\\n1131\\t            assert_eq!(parsed, op);\\n1132\\t        }\\n1133\\t    }\\n1134\\t\\n1135\\t    #[test]\\n1136\\t    fn granted_database_roundtrip() {\\n1137\\t        let db = GrantedDatabase {\\n1138\\t            name: \\\"orders\\\".into(),\\n1139\\t            ops: vec![Op::Read, Op::Write],\\n1140\\t        };\\n1141\\t        let json = serde_json::to_string(\u0026db).unwrap();\\n1142\\t        let parsed: GrantedDatabase = serde_json::from_str(\u0026json).unwrap();\\n1143\\t        assert_eq!(parsed, db);\\n1144\\t    }\\n1145\\t\\n1146\\t    #[test]\\n1147\\t    fn grants_roundtrip() {\\n1148\\t        let grants = Grants {\\n1149\\t            databases: vec![\\n1150\\t                GrantedDatabase {\\n1151\\t                    name: \\\"orders\\\".into(),\\n1152\\t                    ops: vec![Op::Read, Op::Write],\\n1153\\t                },\\n1154\\t                GrantedDatabase {\\n1155\\t                    name: \\\"analytics\\\".into(),\\n1156\\t                    ops: vec![Op::Read],\\n1157\\t                },\\n1158\\t            ],\\n1159\\t        };\\n1160\\t        let json = serde_json::to_string(\u0026grants).unwrap();\\n1161\\t        let parsed: Grants = serde_json::from_str(\u0026json).unwrap();\\n1162\\t        assert_eq!(parsed, grants);\\n1163\\t    }\\n1164\\t\\n1165\\t    #[test]\\n1166\\t    fn grants_validation_passes_for_valid_grants() {\\n1167\\t        let grants = Grants {\\n1168\\t            databases: vec![\\n1169\\t                GrantedDatabase {\\n1170\\t                    name: \\\"orders\\\".into(),\\n1171\\t                    ops: vec![Op::Read, Op::Write],\\n1172\\t                },\\n1173\\t            ],\\n1174\\t        };\\n1175\\t        assert!(grants.validate().is_ok());\\n1176\\t    }\\n1177\\t\\n1178\\t    #[test]\\n1179\\t    fn grants_validation_rejects_empty_database_name() {\\n1180\\t        let grants = Grants {\\n1181\\t            databases: vec![GrantedDatabase {\\n1182\\t                name: \\\"\\\".into(),\\n1183\\t                ops: vec![Op::Read],\\n1184\\t            }],\\n1185\\t        };\\n1186\\t        assert!(matches!(\\n1187\\t            grants.validate(),\\n1188\\t            Err(AuthError::GrantsMalformed)\\n1189\\t        ));\\n1190\\t    }\\n1191\\t\\n1192\\t    #[test]\\n1193\\t    fn grants_validation_rejects_empty_ops() {\\n1194\\t        let grants = Grants {\\n1195\\t            databases: vec![GrantedDatabase {\\n1196\\t                name: \\\"orders\\\".into(),\\n1197\\t                ops: vec![],\\n1198\\t            }],\\n1199\\t        };\\n1200\\t        assert!(matches!(\\n1201\\t            grants.validate(),\\n1202\\t            Err(AuthError::GrantsMalformed)\\n1203\\t        ));\\n1204\\t    }\\n1205\\t\\n1206\\t    #[test]\\n1207\\t    fn grants_validation_rejects_duplicate_ops() {\\n1208\\t        let grants = Grants {\\n1209\\t            databases: vec![GrantedDatabase {\\n1210\\t                name: \\\"orders\\\".into(),\\n1211\\t                ops: vec![Op::Read, Op::Read],\\n1212\\t            }],\\n1213\\t        };\\n1214\\t        assert!(matches!(\\n1215\\t            grants.validate(),\\n1216\\t            Err(AuthError::GrantsMalformed)\\n1217\\t        ));\\n1218\\t    }\\n1219\\t\\n1220\\t    #[test]\\n1221\\t    fn jwt_claims_roundtrip() {\\n1222\\t        let claims = JwtClaims {\\n1223\\t            iss: \\\"axon://eitri.example\\\".into(),\\n1224\\t            sub: \\\"user_01HZ...\\\".into(),\\n1225\\t            aud: \\\"tenant_acme\\\".into(),\\n1226\\t            jti: \\\"cred_01HZ...\\\".into(),\\n1227\\t            iat: 1760000000,\\n1228\\t            nbf: 1760000000,\\n1229\\t            exp: 1760086400,\\n1230\\t            grants: Grants {\\n1231\\t                databases: vec![GrantedDatabase {\\n1232\\t                    name: \\\"orders\\\".into(),\\n1233\\t                    ops: vec![Op::Read, Op::Write],\\n1234\\t                }],\\n1235\\t            },\\n1236\\t        };\\n1237\\t        let json = serde_json::to_string(\u0026claims).unwrap();\\n1238\\t        let parsed: JwtClaims = serde_json::from_str(\u0026json).unwrap();\\n1239\\t        assert_eq!(parsed, claims);\\n1240\\t    }\\n1241\\t\\n1242\\t    // ── aud array-form rejection test (ADR-018 §4) ─────────────────────\\n1243\\t\\n1244\\t    #[test]\\n1245\\t    fn jwt_claims_aud_array_returns_credential_malformed() {\\n1246\\t        // The JWT library would parse aud as an array, but our schema\\n1247\\t        // requires it to be a string. We test this by manually creating\\n1248\\t        // invalid JSON.\\n1249\\t        let invalid_json = r#\\\"{\\n1250\\t            \\\"iss\\\": \\\"axon://eitri.example\\\",\\n1251\\t            \\\"sub\\\": \\\"user_01HZ...\\\",\\n1252\\t            \\\"aud\\\": [\\\"tenant_acme\\\", \\\"tenant_globex\\\"],\\n1253\\t            \\\"jti\\\": \\\"cred_01HZ...\\\",\\n1254\\t            \\\"iat\\\": 1760000000,\\n1255\\t            \\\"nbf\\\": 1760000000,\\n1256\\t            \\\"exp\\\": 1760086400,\\n1257\\t            \\\"grants\\\": {\\\"databases\\\": []}\\n1258\\t        }\\\"#;\\n1259\\t\\n1260\\t        // parse_claims maps serde errors to AuthError::CredentialMalformed.\\n1261\\t        let result = parse_claims(invalid_json);\\n1262\\t        assert!(\\n1263\\t            matches!(result, Err(AuthError::CredentialMalformed)),\\n1264\\t            \\\"aud as array must produce AuthError::CredentialMalformed, got: {:?}\\\",\\n1265\\t            result\\n1266\\t        );\\n1267\\t    }\\n1268\\t\\n1269\\t    // ── TenantRole delegation helper tests ─────────────────────────────\\n1270\\t\\n1271\\t    #[test]\\n1272\\t    fn admin_delegation_ops() {\\n1273\\t        let ops = TenantRole::Admin.delegation_ops();\\n1274\\t        assert_eq!(ops.len(), 3);\\n1275\\t        assert!(ops.contains(\u0026Op::Read));\\n1276\\t        assert!(ops.contains(\u0026Op::Write));\\n1277\\t       