	s.hub.mu.Lock()
	s.hub.registry = federation.NewRegistry()
	if err := s.hub.registry.UpsertSpoke(federation.SpokeRecord{
		NodeID:     "node-a",
		Name:       "alpha",
		URL:        spoke.URL,
		ProjectIDs: []string{"proj-a"},
		Status:     federation.StatusActive,
	}); err != nil {
		s.hub.mu.Unlock()
