+// warnAboutOrphanedHomeState emits a startup warning when legacy
+// home-scoped server or tsnet directories still exist but the active
+// project state root now lives elsewhere.
+func (s *Server) warnAboutOrphanedHomeState() {
+	home, err := os.UserHomeDir()
+	if err != nil {
+		return
+	}
+
+	homeRoot := ddxroot.JoinHome(home)
+	activeRoot, ok := ddxroot.ExistingPath(context.Background(), s.WorkingDir)
+	if !ok {
+		activeRoot = ddxroot.Path(context.Background(), s.WorkingDir)
+	}
+	if filepath.Clean(activeRoot) == filepath.Clean(homeRoot) {
+		return
+	}
+
+	legacyRoots := []struct {
+		kind string
+		path string
+	}{
+		{kind: "server", path: ddxroot.JoinHome(home, "server")},
+		{kind: "tsnet", path: ddxroot.JoinHome(home, "tsnet")},
+	}
+	for _, legacy := range legacyRoots {
+		info, err := os.Stat(legacy.path)
+		if err != nil || !info.IsDir() {
+			continue
+		}
+		fmt.Fprintf(serverStartupWarnWriter,
+			"warning: orphaned legacy %s state at %s; active state root is %s\n",
+			legacy.kind, legacy.path, activeRoot)
+	}
+}
